  ('judicial-d4b276c4-moex-00015', 'judicial-d4b276c4', 'judicial-d4b276c4-moex-113-9140ce03', 'sub-judicial-d4b276c4-01', NULL, 'essay', '甲男與乙女結婚，在乙女安排下，甲收養乙與前夫所生之 5歲丙女，惟
不到三個月，兩人即離婚，約定由乙擔任親權人，乙將丙帶走後，未與
甲有任何往來長達 30 年，甲乃向臺中地方法院提起裁判終止收養，經法
院認為兩造雖為養父女關係，但 30 年來未有如父女般共同生活，徒有收
養形式，足見兩造存在難以維持收養關係之重大事由，而宣告終止收養
關係。試問：
本件向法院聲請宣告終止收養事件屬於家事訴訟事件或非訟事件？
理由何在？法院在程序上應如何審理？（15分）
丙若對於該結果不服，其可請求之救濟管道為何？又丙於救濟審中就
其請求為捨棄時，法院可否終結該程序？（10 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:54+00:00", "source_pdf_sha1": "226396e02d80", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "104", "s": "0421", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "家事事件法", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "家事調查官"}'::jsonb, NULL),
  ('judicial-d4b276c4-moex-00016', 'judicial-d4b276c4', 'judicial-d4b276c4-moex-113-9140ce03', 'sub-judicial-d4b276c4-01', NULL, 'essay', '甲男與乙女結婚，甲男之戶籍於新北市，乙女之戶籍於高雄市，兩人於
新北市登記結婚，婚後未設有共同住所地，甲、乙於婚後之居所仍分別
在新北與高雄，惟甲經常南下與乙同住。於民國（下同）112 年 5 月乙
先因甲未支付扶養費向高雄少年及家事法院（下稱高雄少家法院）請求
甲給付扶養費受理在案，甲後於 112 年 12 月向新北地方法院提起婚姻
無效之訴訟。新北地方法院復將該訴訟裁定移送高雄少家法院，則新北
地方法院裁定移送之依據為何？高雄少家法院於程序上又應如何審
理？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:54+00:00", "source_pdf_sha1": "226396e02d80", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "104", "s": "0421", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "家事事件法", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "家事調查官"}'::jsonb, NULL),
  ('judicial-d4b276c4-moex-00017', 'judicial-d4b276c4', 'judicial-d4b276c4-moex-113-9140ce03', 'sub-judicial-d4b276c4-01', NULL, 'essay', '甲男與乙女婚後育有一子丙，其後甲乙經法院裁判離婚，法院並裁定丙
由甲單獨行使親權，但乙對丙得依裁判之附表進行會面交往。未料其後
甲百般阻礙乙對丙進行探視，故乙向法院請求強制執行，並取得執行名
義，而合法送達至甲，然甲仍未為履行，並聲明丙無意願與乙進行會面，
此時強制執行法院可採行那些措施？又家事調查官在上述措施中應為
何種協力？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:54+00:00", "source_pdf_sha1": "226396e02d80", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "104", "s": "0421", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "家事事件法", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "家事調查官"}'::jsonb, NULL),
  ('judicial-d4b276c4-moex-00018', 'judicial-d4b276c4', 'judicial-d4b276c4-moex-113-9140ce03', 'sub-judicial-d4b276c4-01', NULL, 'essay', '甲男出生後，其父母離異，自小由母乙扶養長大，其父丙從未扶養或照
顧甲，亦未對甲進行探視。甲乃向法院請求免除對丙之扶養義務，丙到
庭後亦自認從未扶養甲，請問在調解程序中，兩造可否請求合意裁定或
適當裁定？理由為何？法院為裁定前應踐行何種程序？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:54+00:00", "source_pdf_sha1": "226396e02d80", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "104", "s": "0421", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "家事事件法", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "家事調查官"}'::jsonb, NULL),
  ('judicial-d4b276c4-moex-00019', 'judicial-d4b276c4', 'judicial-d4b276c4-moex-113-0b2477b6', 'sub-judicial-d4b276c4-02', NULL, 'essay', '英國發展心理學家鮑比（John Bowlby）提出依附理論（attachment
theory），說明主要照顧者照顧嬰兒的方式會讓嬰兒發展出特定的依附
型態。而依附型態所形成之內部運作模式，將影響個人長大後在人際關
係中的感受、想法和期望，後來愛因斯沃斯（MaryAinsworth）透過一
系列研究發展出四種依附型態，獲得世界各地心理學家的重視與廣泛應
用。請回答以下問題：
愛因斯沃斯提出的四種依附型態為何？並請說明每一種依附型態在
成人的人際關係裡可能出現之情緒與行為樣態。（20 分）
何謂依附創傷？並請說明此對成人人際關係的影響。（5分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:54+00:00", "source_pdf_sha1": "992a7079f744", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "104", "s": "0806", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "心理學", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "家事調查官"}'::jsonb, NULL),
  ('judicial-d4b276c4-moex-00020', 'judicial-d4b276c4', 'judicial-d4b276c4-moex-113-0b2477b6', 'sub-judicial-d4b276c4-02', NULL, 'essay', '關於吸毒者的矯治主要有「犯罪說」、「疾病說」兩大派別。特別發生重
大社會案件，如毒蟲向父母要不到錢買毒憤而弒親時，兩派觀點又會引
發鄉民們論戰。請問您對毒癮的成因及矯治方法之觀點為何？請先分別
說明「犯罪說」與「疾病說」之主要重點，再提出您個人的觀點與您認
為有效的矯治方法。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:54+00:00", "source_pdf_sha1": "992a7079f744", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "104", "s": "0806", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "心理學", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "家事調查官"}'::jsonb, NULL),
  ('judicial-d4b276c4-moex-00021', 'judicial-d4b276c4', 'judicial-d4b276c4-moex-113-0b2477b6', 'sub-judicial-d4b276c4-02', NULL, 'essay', '生活中的衝突無所不在，個人也會因為對生活中出現目標之內在動機不
同，而產生心理衝突，勒温（KurtLewin）針對個人內在兩種力量的衝突
提出了三種衝突類型：⑴雙趨衝突，⑵雙避衝突，⑶趨避衝突。請說明
此三種衝突類型之內涵，並分別以「青少年學生輟學加入幫派」為例說
明之。（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:54+00:00", "source_pdf_sha1": "992a7079f744", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "104", "s": "0806", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "心理學", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "家事調查官"}'::jsonb, NULL),
  ('judicial-d4b276c4-moex-00022', 'judicial-d4b276c4', 'judicial-d4b276c4-moex-113-0b2477b6', 'sub-judicial-d4b276c4-02', NULL, 'essay', '主管計劃決策和情緒控管的前額葉皮質（prefrontalcortex）通常在 18 至
25 歲間發展成熟，因此未發展成熟的前額葉皮質會導致正值青春期的青
少年出現某些正向或負向行為。請寫出五項因未成熟前額葉皮質導致青
少年常見的行為特徵或型態，並說明之。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:54+00:00", "source_pdf_sha1": "992a7079f744", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "104", "s": "0806", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "心理學", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "家事調查官"}'::jsonb, NULL),
  ('judicial-d4b276c4-moex-00023', 'judicial-d4b276c4', 'judicial-d4b276c4-moex-113-1a0105ba', 'sub-judicial-d4b276c4-03', NULL, 'essay', '甲生有乙子與丙女，甲死亡時，其名下有 A車、B地及 C存款。惡意之
丁自命為唯一繼承人，不但否認乙、丙之繼承人資格，而且排除乙、丙
對於 A車、B地之管理，逕自占有、使用收益，又擅自提領 C存款。十
年後，乙、丙依繼承回復請求權以及所有物返還請求權之規定，訴請丁
返還 A 車與 B 地，復依侵權行為以及不當得利之規定，訴請丁返還存
款。對此，丁以前揭請求權均已罹於消滅時效為由而拒絕返還。請問丁
拒絕返還，是否有理？（30分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:54+00:00", "source_pdf_sha1": "158c128bf78c", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "104", "s": "0403", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法總則與親屬、繼承編", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "家事調查官"}'::jsonb, NULL),
  ('judicial-d4b276c4-moex-00024', 'judicial-d4b276c4', 'judicial-d4b276c4-moex-113-1a0105ba', 'sub-judicial-d4b276c4-03', NULL, 'essay', '甲男乙女為夫妻，生有丙女，甲乙其後離婚，約定未成年子女丙之監護
權由乙行使之。甲嗣與丁女結婚，並收養丁與前夫所生之戊女。甲另與
有夫之婦過從親密，生下己男，甲對己照料有加。甲復與未婚女子譜出
戀情，生下庚女，但甲對庚未曾聞問。俟丁查知上情，甲遭丁故意下毒
致死，惟甲於臨終前以遺囑指定其母辛為丙之監護人。請問誰是甲之繼
承人？誰又是丙之監護人？（35分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:54+00:00", "source_pdf_sha1": "158c128bf78c", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "104", "s": "0403", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法總則與親屬、繼承編", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "家事調查官"}'::jsonb, NULL)
